export default function CodeBlock({
    language,
    children
}) {
    if (typeof children === 'string') {
        children = children.replace(/^(\s*\n)+/, '').replace(/\s+$/, '');
    }

    return (
        <SyntaxHighlighter language={language} style={theme}>
            {children}
        </SyntaxHighlighter>
    );
}